import{_ as i,c as l,o as a,ag as e}from"./chunks/framework.DK1-H3E1.js";const p=JSON.parse('{"title":"知识蒸馏（Knowledge Distillation）入门","description":"","frontmatter":{"order":20},"headers":[],"relativePath":"ai/knowledge-distillation.md","filePath":"ai/knowledge-distillation.md","lastUpdated":1772197851000}'),o={name:"ai/knowledge-distillation.md"};function r(n,t,s,d,h,u){return a(),l("div",null,t[0]||(t[0]=[e('<h1 id="知识蒸馏-knowledge-distillation-入门" tabindex="-1">知识蒸馏（Knowledge Distillation）入门 <a class="header-anchor" href="#知识蒸馏-knowledge-distillation-入门" aria-label="Permalink to &quot;知识蒸馏（Knowledge Distillation）入门&quot;">​</a></h1><blockquote><p>📅 主题：把“大模型能力”迁移到“小模型”的核心方法</p></blockquote><h2 id="一、什么是知识蒸馏" tabindex="-1">一、什么是知识蒸馏 <a class="header-anchor" href="#一、什么是知识蒸馏" aria-label="Permalink to &quot;一、什么是知识蒸馏&quot;">​</a></h2><p><strong>知识蒸馏（Knowledge Distillation）</strong> 是一种模型压缩与能力迁移方法：<br> 让一个性能更强的 <strong>教师模型（Teacher）</strong> 指导一个更小、更快的 <strong>学生模型（Student）</strong> 学习，从而在较低成本下保留尽可能多的效果。</p><p>核心目标是三件事：</p><ol><li><strong>降成本</strong>：推理更快、显存占用更低</li><li><strong>保效果</strong>：尽量接近教师模型性能</li><li><strong>易部署</strong>：适配边缘端、移动端或高并发服务</li></ol><hr><h2 id="二、为什么蒸馏有效" tabindex="-1">二、为什么蒸馏有效 <a class="header-anchor" href="#二、为什么蒸馏有效" aria-label="Permalink to &quot;二、为什么蒸馏有效&quot;">​</a></h2><p>直接用硬标签训练（只告诉“对/错”）信息很少。<br> 教师模型给学生的“软目标”通常更丰富，例如：</p><ul><li>类别概率分布（不仅是 top1）</li><li>中间层表示</li><li>注意力模式</li></ul><p>这些信号包含“类间相似性”和教师的归纳偏好，能帮助学生学习到更平滑、更泛化的决策边界。</p><hr><h2 id="三、基本训练范式" tabindex="-1">三、基本训练范式 <a class="header-anchor" href="#三、基本训练范式" aria-label="Permalink to &quot;三、基本训练范式&quot;">​</a></h2><p>经典蒸馏损失通常由两部分组成：</p><ol><li><strong>监督损失</strong>（学生 vs 真实标签）</li><li><strong>蒸馏损失</strong>（学生 vs 教师输出）</li></ol><p>常见形式（分类）：</p><ul><li>总损失 = <code>α * CE(y_true, y_student) + (1-α) * KL(p_teacher^T || p_student^T)</code></li><li><code>T</code> 是温度（Temperature），用于软化概率分布</li></ul><h3 id="温度-t-的作用" tabindex="-1">温度 T 的作用 <a class="header-anchor" href="#温度-t-的作用" aria-label="Permalink to &quot;温度 T 的作用&quot;">​</a></h3><ul><li><code>T</code> 越高，分布越平滑，能暴露更多“次优类别信息”</li><li>训练后推理时通常用 <code>T=1</code></li></ul><hr><h2 id="四、常见蒸馏类型" tabindex="-1">四、常见蒸馏类型 <a class="header-anchor" href="#四、常见蒸馏类型" aria-label="Permalink to &quot;四、常见蒸馏类型&quot;">​</a></h2><h2 id="_4-1-响应蒸馏-logits-distillation" tabindex="-1">4.1 响应蒸馏（Logits Distillation） <a class="header-anchor" href="#_4-1-响应蒸馏-logits-distillation" aria-label="Permalink to &quot;4.1 响应蒸馏（Logits Distillation）&quot;">​</a></h2><p>最常见，学生拟合教师输出 logits 或 softmax 分布。<br> 实现简单，适合作为基线。</p><h2 id="_4-2-特征蒸馏-feature-distillation" tabindex="-1">4.2 特征蒸馏（Feature Distillation） <a class="header-anchor" href="#_4-2-特征蒸馏-feature-distillation" aria-label="Permalink to &quot;4.2 特征蒸馏（Feature Distillation）&quot;">​</a></h2><p>学生对齐教师中间层特征（hidden states）。<br> 适合提升表示学习能力，常用于视觉、语音、NLP 编码器任务。</p><h2 id="_4-3-注意力蒸馏-attention-distillation" tabindex="-1">4.3 注意力蒸馏（Attention Distillation） <a class="header-anchor" href="#_4-3-注意力蒸馏-attention-distillation" aria-label="Permalink to &quot;4.3 注意力蒸馏（Attention Distillation）&quot;">​</a></h2><p>让学生学习教师的注意力图或关系矩阵。<br> 常用于 Transformer 系列模型压缩。</p><h2 id="_4-4-任务蒸馏-task-specific-distillation" tabindex="-1">4.4 任务蒸馏（Task-specific Distillation） <a class="header-anchor" href="#_4-4-任务蒸馏-task-specific-distillation" aria-label="Permalink to &quot;4.4 任务蒸馏（Task-specific Distillation）&quot;">​</a></h2><p>在特定任务数据上蒸馏（如检索、分类、问答），可获得更高任务收益。</p><hr><h2 id="五、llm-场景下的蒸馏实践" tabindex="-1">五、LLM 场景下的蒸馏实践 <a class="header-anchor" href="#五、llm-场景下的蒸馏实践" aria-label="Permalink to &quot;五、LLM 场景下的蒸馏实践&quot;">​</a></h2><p>在大模型时代，蒸馏常见用途：</p><ol><li><p><strong>离线批量生成伪标签</strong><br> 用强模型给数据打标，学生学习这些高质量“教师答案”。</p></li><li><p><strong>指令蒸馏（Instruction Distillation）</strong><br> 教师在大量指令任务上生成输出，学生学习“遵循指令”的行为模式。</p></li><li><p><strong>推理链蒸馏（Reasoning Distillation）</strong><br> 学习教师的解题步骤或结构化推理过程（可配合 CoT / 自检策略）。</p></li><li><p><strong>多任务蒸馏</strong><br> 一个学生统一吸收多个任务或多个教师模型能力。</p></li></ol><hr><h2 id="六、蒸馏-vs-微调-vs-量化" tabindex="-1">六、蒸馏 vs 微调 vs 量化 <a class="header-anchor" href="#六、蒸馏-vs-微调-vs-量化" aria-label="Permalink to &quot;六、蒸馏 vs 微调 vs 量化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方法</th><th>主要目标</th><th>典型收益</th><th>典型代价</th></tr></thead><tbody><tr><td>蒸馏</td><td>小模型学大模型能力</td><td>速度快、部署友好</td><td>需要教师推理与蒸馏训练</td></tr><tr><td>微调</td><td>让模型适配特定任务</td><td>精度提升明显</td><td>推理成本不一定下降</td></tr><tr><td>量化</td><td>降低模型精度位宽</td><td>显存/吞吐优化</td><td>可能有精度损失</td></tr></tbody></table><p>实际工程中常组合使用：</p><ul><li>先蒸馏得到小模型</li><li>再做量化与推理优化</li></ul><hr><h2 id="七、工程落地要点" tabindex="-1">七、工程落地要点 <a class="header-anchor" href="#七、工程落地要点" aria-label="Permalink to &quot;七、工程落地要点&quot;">​</a></h2><h2 id="_7-1-先定义目标指标" tabindex="-1">7.1 先定义目标指标 <a class="header-anchor" href="#_7-1-先定义目标指标" aria-label="Permalink to &quot;7.1 先定义目标指标&quot;">​</a></h2><p>蒸馏不是“越像教师越好”，要看业务目标：</p><ul><li>延迟（P95）</li><li>吞吐（QPS）</li><li>成本（GPU/CPU 单位请求成本）</li><li>任务准确率 / 召回率 / 用户满意度</li></ul><h2 id="_7-2-数据质量比技巧更重要" tabindex="-1">7.2 数据质量比技巧更重要 <a class="header-anchor" href="#_7-2-数据质量比技巧更重要" aria-label="Permalink to &quot;7.2 数据质量比技巧更重要&quot;">​</a></h2><p>高质量蒸馏数据（覆盖场景、标签可靠）往往比复杂损失设计更关键。</p><h2 id="_7-3-学生模型容量要合适" tabindex="-1">7.3 学生模型容量要合适 <a class="header-anchor" href="#_7-3-学生模型容量要合适" aria-label="Permalink to &quot;7.3 学生模型容量要合适&quot;">​</a></h2><p>学生太小会出现“容量瓶颈”，学不动教师能力；<br> 太大又失去降本意义。要在效果与成本间平衡。</p><h2 id="_7-4-分阶段训练更稳" tabindex="-1">7.4 分阶段训练更稳 <a class="header-anchor" href="#_7-4-分阶段训练更稳" aria-label="Permalink to &quot;7.4 分阶段训练更稳&quot;">​</a></h2><p>可采用：</p><ol><li>先做 logits 蒸馏（打基础）</li><li>再加任务监督或特征蒸馏（提上限）</li></ol><hr><h2 id="八、常见问题与规避" tabindex="-1">八、常见问题与规避 <a class="header-anchor" href="#八、常见问题与规避" aria-label="Permalink to &quot;八、常见问题与规避&quot;">​</a></h2><ol><li><p><strong>学生学不动</strong></p><ul><li>调整温度 T、loss 权重 α</li><li>增加学生容量或改蒸馏层对齐策略</li></ul></li><li><p><strong>离线指标好，线上效果差</strong></p><ul><li>训练集分布与线上不一致</li><li>需做线上回放数据蒸馏和 A/B 验证</li></ul></li><li><p><strong>蒸馏后任务偏科</strong></p><ul><li>多任务数据不平衡</li><li>需重采样或任务加权</li></ul></li><li><p><strong>收益不明显</strong></p><ul><li>仅做蒸馏未做推理侧优化</li><li>结合量化、编译优化、缓存策略才能放大收益</li></ul></li></ol><hr><h2 id="九、小结" tabindex="-1">九、小结 <a class="header-anchor" href="#九、小结" aria-label="Permalink to &quot;九、小结&quot;">​</a></h2><ol><li>知识蒸馏的本质是“让小模型学习大模型的知识分布与行为模式”。</li><li>经典做法是监督损失 + 蒸馏损失，温度 T 用于软化信息。</li><li>在 LLM 场景中，指令蒸馏和推理蒸馏是高价值方向。</li><li>蒸馏不是孤立技术，通常与量化、推理优化联合使用。</li><li>成功落地的关键是：明确业务指标、保证数据质量、做线上闭环验证。</li></ol><p>当你想在成本受限条件下保留大模型体验，知识蒸馏通常是第一批应考虑的核心手段。</p>',57)]))}const b=i(o,[["render",r]]);export{p as __pageData,b as default};
